<template>
    <q-checkbox v-model="model" :dense="true" @update:modelValue="update" />
</template>
<script lang="ts">
export default {
    name:"AdminBoolean",
    props:{
        props: {
            type: String,
            required: true
        },
        },
    data(){
        return{
            model: this.props?this.props.src:""
        }
    },
    computed:{
      
    },
    methods:{

        update(){
            console.log(this.model)
            var payload = {
                index: this.props.index,
                value: this.model,
                col: this.props.col
            }
            this.$emit('update',payload)
        }
    }
}
</script>